013122514096446386ba93803077dca7','Gebrehiwet Gebremedhin Tesfahun','Male',40,'Tahtay Adiyabo, Shembelina (ወረዳ ታሕታይ ኣድያቦ ጣብያ ሸምበሊና)','Family Members and Relatives','Family Members and Relatives','Killed by Eritrean forces',NULL,'Killed by the Eritrean soldiers. He was a farmer.','civilian_victims_pic/default.png','2024-10-13 15:18:09.184678','North Western Tigray',NULL,NULL,NULL,NULL,1,63,'Tahtay Adiyabo'),('01473707d5c54384a6339b5f81e62fb6','Hiluf Michael Mehari','Male',NULL,'Alamata','Family Members and Relatives, Reuters, Twitter','Family Members and Relatives, https://www.reuters.com/world/africa/impoverished-ethiopia-seeks-extra-25-bln-rebuild-war-2021-12-30/, https://x.com/FilippoGrandi/status/1476491445062225924','Killed by Ethiopian forces','2021-12-19','Killed by a drone attack on his way from Alamata to Mekelle on December 19, 2021. According to his family members and colleagues, he was a staff member of the Office of the United Nations High Commissioner for Refugees (UNHCR), Mekelle branch, and served for more than nine years.','civilian_victims_pic/Hiluf_Michael_Mehari.jpeg','2024-07-25 19:05:33.262816','Southern Tigray',NULL,NULL,NULL,NULL,1,63,'Alamata'),('014d256edac845708e1c7c23be284cf4','Gebreselassie Gebrehiwet Gebremariam','Male',58,'Embaseneyti, Meryeto (ጣብያ መርየቶ)','Family Members and Relatives','Family Members and Relatives','Killed by Ethiopian and Eritrean forces',NULL,'Killed by the Eritrean and Ethiopian soldiers.','civilian_victims_pic/default.png','2024-05-15 16:44:38.432832','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Emba Seneyti'),('016bb08030d34a8b80e8828e556d08cc','Daniel Hailemariam','Male',20,'Dengelat (ወረዳ ሳዕሲዕ, ጣብያ በለሶ, ቁሸት ደንገላት)','Family Members and Relatives','Family Members and Relatives','Killed by Eritrean forces','2020-11-30','Among the hundreds of civilians killed by the Eritrean soldiers inside Saint Mary’s Church in Dengelat on November 30, 2020. ','civilian_victims_pic/default.png','2024-04-15 13:31:24.932849','Eastern Tigray',NULL,NULL,NULL,NULL,1,63,'Saesie'),('016ff1a165404447a031d66b7e63ed17','Haftu Berihun','Male',NULL,'Alamata','Family Members and Relatives','Family Members and Relatives','Killed by Ethiopian forces','2021-04-14','Killed by the Ethiopian soldiers on April 14, 2021. He was a contractor and a father of 4.','civilian_victims_pic/default.png','2024-06-13 13:15:21.432845','Southern Tigray',NULL,NULL,NULL,NULL,1,63,'Alamata'),('019e38efb671465f83b59d77c37b6f9f','Shashuworku Mekonen','Female',NULL,'Newi, Kola Tembien','Family Members and Relatives','Family Members and Relatives','Killed by Ethiopian forces','2021-05-01','Killed by the Ethiopian soldiers on May 01, 2021.','civilian_victims_pic/default_female.jpg','2024-07-14 13:45:50.530333','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Kola Tembien'),('01b523c98dfd488395ab58d73a3b0e55','Mizan Teka','Female',NULL,'Kilte Awulaelo District','Family Members and Relatives','Family Members and Relatives','Killed by Ethiopian and Eritrean forces',NULL,'Killed by the Ethiopian and Eritrean soldiers in the district of Kilte Awulaelo, Genfel, Dengolo (ጣብያ ገንፈል ቁሸት ደንጎሎ).','civilian_victims_pic/default_female.jpg','2024-07-25 14:49:11.839407','Eastern Tigray',NULL,NULL,NULL,NULL,1,63,'Kilte Awulaelo'),('01b8f2f640b94f2bbafbacbca45776aa','Tesfay Asgedom','Male',80,'Ahferom, Mishig (ጣብያ ምሽግ( ሃንየን)','Family Members and Relatives','Family Members and Relatives','Died from lack of medicine',NULL,'Died due to a lack of medicine in the hospital.','civilian_victims_pic/default.png','2024-07-20 15:13:54.064331','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Ahferom'),('01c9b94300c540489b2e0ecfff690fe3','Keshi Gebremichael Abraha (Priest)','Male',NULL,'Axum','Family Members and Relatives','Family Members and Relatives','Killed by Eritrean forces',NULL,'Killed by the Eritrean soldiers.  He was a priest.','civilian_victims_pic/default.png','2024-04-23 23:18:03.600815','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Axum'),('01cf1dffb39e40358d69500151