NULL,1,63,'Naeder'),('27daefb950ae4e03aacbf2b1660b5b6c','Kide Gebreyohannes Gebretsadki (with his father and two brothers)','Male',NULL,'Adwa, Enda Mariam Shewito, ዓዲ ስገም','Family Members and Relatives, The Washington Post, The Guardian','Family Members and Relatives, https://www.washingtonpost.com/world/2023/02/28/ethiopia-massacre-tigray-eritrea/, https://www.theguardian.com/global-development/2023/apr/20/the-hyenas-had-eaten-the-rest-survivors-speak-about-the-horrors-of-massacres-in-northern-tigray','Killed by Eritrean forces',NULL,'Kide Gebreyohannes was among the civilians massacred around Mariam Shewito by the Eritrean forces. He was killed along with his father, Gebreyohannes Gebretsadik, and two of his brothers, Tekle Gebreyohannes Gebretsadik Gebreyesus, and Endrias Gebreyohannes Gebretsadik Gebreyesus.','civilian_victims_pic/default.png','2024-10-11 23:13:20.557043','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Adwa'),('27fe6df5ec994c1abaafa1732b238f75','Tilahun Asgedom','Male',53,'Wukro Maray','Family Members and Relatives','Family Members and Relatives','Killed by Eritrean forces','2020-11-19','Killed by the Eritrean soldiers on November 19, 2020. Burial place: እንዳ ኣቡነ ኣረጋዊ ቤተ ክርስትያን.','civilian_victims_pic/default.png','2024-06-03 16:37:26.822642','Central Tigray',NULL,NULL,NULL,NULL,1,63,'Tahtay Maichew'),('28086a32dfc049a58b23fd254fddaf5b','Gebrekidan Hadush Gebremedhin','Male',NULL,'Degua Tembien, Togoga','Family Members and Relatives, The Guardian, CNN','Family Members and Relatives, https://www.theguardian.com/world/2021/jun/24/ethiopian-airstrike-tigray-market, https://www.cnn.com/2021/06/23/world/tigray-airstrike-market-ambulances-intl/index.html','Killed by Ethiopian forces','2021-06-22','Killed in the Togoga market air strike massacres. The Ethiopian Air Force bombed the Togoga market in Degua Tembien on June 22, 2021.','civilian_victims_pic/default.png','2024-08-04 19:27:38.909561','South Eastern Tigray',NULL,NULL,NULL,NULL,1,63,'Degua Tembien'),