INSERT INTO `App_unverified_civilian` VALUES ('07cecd22cc1b4097a5880a5a04f6d73a','Tekeze River',43,'The Associated Press (AP)','https://apnews.com/article/middle-east-africa-united-nations-only-on-ap-b11ad4a5c863a18155c7ee35043615dc','2024-10-18 00:42:54.631454','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','\"In the last one week, 43 bodies were buried around this river,” the surgeon from the nearby Tigray town of Humera, Tewodros Tefera, told the AP. He and other refugees believe the bodies were dumped into the river at Humera, which has seen some of the worst violence since the war began in November.\" [The Associated Press (AP)]'),('1266286934af4459af83f2652ba59fcf','Tahtay Adiyabo, Shembelina (ወረዳ ታሕታይ ኣድያቦ ጣብያ ሸምበሊና)',2,'Witnesses','Witnesses','2024-10-13 15:39:47.217148','Killed by Eritrean forces','Tahtay Adiyabo','North Western Tigray','Aboy Weyni (80), a farmer, was killed along with his two sons. '),('1ab0d4012f834e599eb5150b65e34599','Within reach of the Sudanese border',2,'Human Rights Watch','https://www.hrw.org/news/2020/12/23/interview-uncovering-crimes-committed-ethiopias-tigray-region','2024-04-08 23:14:41.107522','Killed by Amhara militia and Fano','Other','Other','Killed by the Amhara militia and Fano. \"The same young man broke down at the end of our interview as he described how two of his friends whom he had escaped with were shot dead by Amhara Liyu Hail when they were within reach of the Sudanese border.\" [Human Rights Watch Interview]'),('2b90e719e621410eba11a6ef1ffe992c','Wukro',5,'Family Members and Relatives','https://twitter.com/beberekettt/status/1338854609251491848','2024-04-09 17:33:58.562037','Killed by Eritrean forces','Wukro','Eastern Tigray','Birhane Alemtsehay was killed along with 5 of his friends by the Eritrean soldiers in one room in Wukro.'),('2c188cf09bb2411f80ea142e1ad5fa2d','Alasa, Degua Tembien',4,'Family Members and Relatives','https://m.facebook.com/story.php?story_fbid=3786291074741837&id=100000829448686','2024-04-09 17:23:25.828361','Killed by Ethiopian forces','Degua Tembien','South Eastern Tigray','Mr. Leul Gebremedhin (50), along with his 4 friends, was killed by the Ethiopian soldiers in Alasa, Degua Tembien.'),('3ba62b5d86b045448fb3f531f9a5ec1d','Humera',15,'The Guardian','https://www.theguardian.com/global-development/2020/dec/02/tigray-war-refugees-ethiopia-sudan','2024-04-09 17:03:19.283462','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','Tedros, a Dr. from Humera said has received 15 dead civilians on the first day of shelling on 8 November. \"But those who were not brought to the hospital, who died on the streets or at home, were uncountable,? Dr. Tedros said. [The Guardian]'),('3c9b85ef672945519c440f2bcabe587a','Kola Tembien',182,'The Telegraph','https://www.telegraph.co.uk/global-health/terror-and-security/bodies-torn-pieces-ethiopian-eritrean-troops-accused-massacre/','2024-06-13 13:57:38.616451','Killed by Ethiopian and Eritrean forces','Kola Tembien','Central Tigray','\"In exclusive testimony shared with the Telegraph, 18 witnesses told how Ethiopian federal soldiers and Eritrean troops surrounded the area and went from house to house killing a total of 182 people. I saw dead bodies scattered, bodies half-eaten by dogs. The soldiers did not allow anyone to get close to the corpses,” said 26-year-old Tesfay Gebremedhin from the village of Semret, who fled into the mountains along with many other terrified young men.\" [The Telegraph]'),('564f56c3366b443fa1f4f5939c25e3a8','Tekeze River',45,'Al Jazeera Media Network','https://www.aljazeera.com/news/2021/8/3/dozens-bodies-found-river-between-ethiopias-tigray-and#:~:text=At%20least%2030%20corpses%20have,they%20had%20retrieved%20the%20bodies.','2024-10-18 00:36:20.408748','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','\"At least 30 corpses have washed up on the Sudanese banks of a river that abuts Ethiopia’s northern region of Tigray, according to two Ethiopian refugees and four Sudanese witnesses who told Reuters news agency on Monday they had retrieved the bodies. Dr Tewodros Tefera, a surgeon who escaped from the Ethiopian border town of Humera, told Reuters he had buried 10 bodies over the past six days in Sudan and was told by local fishermen and refugees another 28 had been recovered, including seven on Monday. \"They were shot in their chest, abdomen, legs … and also had their hands tied,\" he said adding that he had been able, with the help of refugees, to identify three bodies belonging to Tigrayans from Humera.\" [Al Jazeera]'),('56aea441d7d64542a2842a4cdc631cfc','Wukro',4,'Doctors Without Borders (MSF)','https://www.doctorswithoutborders.org/latest/ethiopia-msf-staff-attacked-after-witnessing-killings-soldiers-tigray','2024-06-03 22:03:06.310222','Killed by Ethiopian forces','Wukro','Eastern Tigray','\"We are horrified by the continued violence in Tigray, Ethiopia. This includes the extrajudicial killings of at least four men who were dragged off public buses and executed by soldiers, while our staff members were present, on Tuesday, March 23, 2021\" reported MSF (Doctors Without Borders) '),('637b54e472fc457898a77b981f407b97','Adi Hageray',2,'Witnesses, TGHAT','Witnesses, https://www.tghat.com/2021/03/19/a-preliminary-report-on-an-adi-hageray-massacre/','2024-05-26 16:18:02.125178','Killed by Ethiopian and Eritrean forces','Adi Hageray','North Western Tigray','The Ethiopian and Eritrean soldiers killed Aba Mehari and 2 unidentified people between November 12, 2020, and November 18, 2020.'),('68a84d837fd94022b51b0c0d169ba908','Adi Hageray, Zagir',8,'Witnesses, TGHAT','Witnesses, https://www.tghat.com/2021/03/19/a-preliminary-report-on-an-adi-hageray-massacre/','2024-05-26 15:17:54.708177','Killed by Ethiopian forces','Adi Hageray','North Western Tigray','8 unidentified people were killed between November 12, 2020, and November 18, 2020, and buried in Zagir, Adi Hageray.'),('85537019c02945d5984ed69f807d8dfa','Humera',3,'New York Times','https://www.nytimes.com/2020/12/09/world/africa/ethiopia-tigray-sudan.html','2024-04-09 16:54:38.056324','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','Killed by the Amhara militia and Fano. Mr. Ashenafi Hailu, a survivor and a refugee in Sudan, told the New York Times.'),('896964958d19474c9935902ebdddb853','Degua Tembien, Togoga',64,'The Guardian','https://www.theguardian.com/world/2021/jun/24/ethiopian-airstrike-tigray-market','2024-08-04 19:22:50.946347','Killed by Ethiopian forces','Degua Tembien','South Eastern Tigray','At least 64 people dead after a market air strike on June 22, 2021, that wounded at least 180, say local officials'),('8d4ba3393638434d9cc6294a425a606a','Cheli, Saharti Samre District',2,'Sky News','https://news.sky.com/story/ethiopia-hundreds-executed-thousands-homeless-the-human-cost-of-fighting-in-tigray-12247307','2024-05-20 15:01:52.166790','Killed by Ethiopian and Eritrean forces','Saharti','South Eastern Tigray','A 25-year-old named Haileselassie Kiros told Sky News that his two brothers had been shot by Ethiopian and Eritrean soldiers.'),('8fe3f5499e724a1aaf374a3e12e3ba19','Shire',2,'Human Rights Watch','https://www.hrw.org/news/2020/12/23/interview-uncovering-crimes-committed-ethiopias-tigray-region','2024-04-08 23:11:45.177566','Killed by Ethiopian and Eritrean forces','Shire Indasilassie','North Western Tigray','Killed by heavy artillery shelling in Shire, carried out by the Ethiopian and Eritrean soldiers. \"While many of the stories we heard were heart-wrenching, one in particular stands out. A young man, a minibus driver, told us about seeing a friend?s two young children, aged 6 and 10, lying dead on the streets in the town of Shire. They had been killed during what he described as heavy shelling of the town.\" [Human Rights Watch Interview]'),('9ae43e470a7f4eb48e11b7c3e1b3e8d7','Tekeze River',14,'CNN','https://www.cnn.com/2021/09/05/africa/ethiopia-tigray-humera-sudan-bodies-cmd-intl/index.html','2024-10-18 00:39:06.317255','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','\"On a trip to Wad El Hilou, a Sudanese town near the border with Ethiopia, a CNN team counted three bodies in one day. Witnesses and local authorities in Sudan confirmed that in the days after the team’s departure, 11 more bodies arrived downstream. Evidence indicates the dead are Tigrayans. Witnesses on the ground say the bodies tell a dark story of mass detentions and mass executions across the border in Humera, a town in Ethiopia’s Tigray region.\" [CNN]'),('9e5caf8dc76649afb28cae6085159ea4','Adi Hageray, Zagir',4,'Witnesses, TGHAT','Witnesses, https://www.tghat.com/2021/03/19/a-preliminary-report-on-an-adi-hageray-massacre/','2024-05-26 15:13:05.426757','Killed by Ethiopian forces','Adi Hageray','North Western Tigray','4 unidentified people were killed between November 12, 2020, and November 18, 2020, and buried behind a church in Zagir, Adi Hageray.'),('a07ee0437d1c48f9a8921b57049dc516','Guba, Benishangul-Gumuz',3,'Family Members and Relatives, The Associated Press (AP)','Family Members and Relatives, https://apnews.com/article/ethiopia-africa-social-media-media-1856cea81ff90d25772777b02292743d','2024-08-05 18:53:27.233804','Killed by Amhara militia and Fano','Other','Other','Three Tigrayan civilians in the Guba area of the Benishangul-Gumuz region were dragged and burned alive, as shown in a video that circulated on social media.'),('a2deee67a3f64dc9a08a7daf7da6da68','Dedebit, Asgede District',26,'Witnesses','Witnesses','2024-07-25 18:47:20.787452','Killed by Eritrean forces','Asgede','North Western Tigray','Getahun Asgedom was killed by Eritrean soldiers. According to his wife, he was shot and killed along with 26 other Tigrayan youths in Dedebit, in the district of Asgede.'),('ada40d2d91984ac792ab668bd944cbed','Adigrat',15,'Witnesses','https://www.facebook.com/alulasolomonk/posts/3781525231885088','2024-04-09 17:30:24.422562','Killed by Eritrean forces','Adigrat','Eastern Tigray','Tesfu Wedajo (Deacon), along with other 15 civilians, was killed by the Eritrean soldiers while he was trying to protect the Addis Pharmaceutical Factory from looting.'),('b14a4781ec7848618e0cb0642ed50619','Hawzen, Measho Preparatory School',11,'Witnesses','Witnesses','2024-06-21 19:30:51.758428','Killed by Ethiopian forces','Hawzen','Eastern Tigray','Witnesses said that Mehari Gebreegziabher Weldeab was killed by Ethiopian soldiers inside Measho Preparatory School in Hawzen. His body was found after 40 days, along with those of 11 other unidentified civilians.'),('b6a44e4a32ab4fd3a6fc0fba4e2f3ba9','Bisober, Chercher, Southern Tigray',27,'France 24, Daily Mail','https://www.france24.com/en/live-news/20201215-terrified-survivors-recount-attacks-on-civilians-in-tigray, https://www.dailymail.co.uk/wires/afp/article-9054001/Terrified-survivors-recount-attacks-civilians-Tigray.html','2024-04-07 19:58:50.422014','Killed by Ethiopian forces','Chercher','Southern Tigray','Killed by the Ethiopian soldiers. \"A 15-year-old boy who leapt in front of a bullet in a futile bid to save his father was also killed. The killings -- which took place on November 14, 10 days after Abiy announced the offensive -- represent just one incident of civilian suffering in Bisober, a farming village home to roughly 2,000 people in southern Tigray. In the three days it took federal forces to wrest control of the village from the TPLF, 27 civilians died, according to local officials and residents: 21 from shelling and six in extrajudicial killings.\" [France 24 and Daily Mail]'),('be75f0363f75422dbc521eecd7a747f7','Miri\'ena, Southwest of Axum',50,'Family Members and Relatives','https://twitter.com/getahun27428036/status/1358761595493625856','2024-04-25 23:12:58.900918','Killed by Eritrean forces','Axum','Central Tigray','Gebremariam Tsehaye was killed by the Eritrean soldiers on February 02, 2021. He was one of around 50 civilians, mostly men, massacred by the Eritrean soldiers in a village called Miri\'ena (Southwest of Axum City).'),('c2e53728fc5a4520b1a8c9f2e8abb925','Adi Hageray',6,'Witnesses, TGHAT','Witnesses, https://www.tghat.com/2021/03/19/a-preliminary-report-on-an-adi-hageray-massacre/','2024-05-26 16:11:54.729864','Killed by Ethiopian and Eritrean forces','Adi Hageray','North Western Tigray','6 unidentified people were found dead inside a high school in Adi Hageray. They were killed by Ethiopian and Eritrean soldiers between November 12, 2020, and November 18, 2020.'),('c84d2eb1d87143fdad6771377094d81a','Humera',12,'New York Times','https://www.nytimes.com/2020/12/09/world/africa/ethiopia-tigray-sudan.html','2024-04-09 16:59:03.049130','Killed by Amhara militia and Fano','Setit Humera','Western Tigray','Killed by the Amhara militia and Fano. Meles, a refugee in Sudan, Daniel Yemane, a refugee in Sudan, and others told the New York Times that they had seen dozens of bodies along the route as they fled their shops, homes, and farms and took to the long road to the border with Sudan, in stifling heat.'),('caddd987a34d488b8a82d6a02cfa15fa','Adi Qeweylo (ዓዲ ቐወይሎ), Tembien',8,'Family Members and Relatives','https://twitter.com/beberekett/status/1339005985067851776','2024-04-09 17:36:48.621008','Killed by Ethiopian and Eritrean forces','Degua Tembien','South Eastern Tigray',' Keshi Yemane (42) and eight other priests were killed by Ethiopian and Eritrean soldiers.'),('db3e81d3472347e0a24020b4875d4680','Ofla District, Mai Maedo, Simret (Becheka village) (ወረዳ ኦፍላ ፣ ቑሸት በጨቓ ጣብያ ስምረት)',2,'Tweet','https://twitter.com/FitwiDesta/status/1370353884061962242','2024-05-20 13:30:52.797141','Killed by Ethiopian and Eritrean forces','Ofla','Southern Tigray','Killed when Ethiopian and Eritrean fighter jets bombed civilians who had gathered for a marriage ceremony in Becheka village, Ofla District.'),('e2395a0573f7488e87882f3268111178','Wukro',4,'Family Members and Relatives','https://www.facebook.com/meiron.yemaryamlij/posts/1907079692785546','2024-05-15 17:33:51.174958','Killed by Ethiopian forces','Wukro','Eastern Tigray','Nesredin Kedir was brutally killed along with 4 other people in the city of Wukro on March 14, 2021.'),('e78f96cd16be47dfb87a860fa2b8a9f0','Adi Hageray',3,'Witnesses, TGHAT','Witnesses, https://www.tghat.com/2021/03/19/a-preliminary-report-on-an-adi-hageray-massacre/','2024-05-26 16:16:36.549004','Killed by Ethiopian and Eritrean forces','Adi Hageray','North Western Tigray','The Ethiopian and Eritrean soldiers killed Aba Engida Kidane and 3 unidentified people between November 12, 2020, and November 18, 2020.'),('ea4c426770f74e4ca6397abb9b86d938','Mekelle',4,'VOA News','https://www.voanews.com/a/ethiopian-government-launches-airstrike-on-tigray-capital-mekelle/6718161.html','2024-06-06 19:52:08.099881','Killed by Ethiopian forces','Mekelle Town','Mekelle Special','On August 26, 2022, an Ethiopian government airstrike hit a children\'s playground in Mekelle. According to a doctor at a Mekelle hospital, who later spoke to the Reuters news agency, the airstrike resulted in the tragic loss of at least four civilian lives. Among those killed, 2 were children.'),('eefd3d0289a449d99284550019b39d03','Selekhlekha (ሰለኽለኻ)',30,'Witnesses','https://www.facebook.com/YirgaGm/posts/443729476712927','2024-06-05 23:46:20.222157','Killed by Eritrean forces','Selekleka','North Western Tigray','In addition to Mebrahtom Gebreegziabher (Wedi Gegey)  and Mulu Gebreegziabher (brothers and both teachers), more than 30 unidentified civilians in the same area were executed by the Eritrean soldiers on March 24, 2021 and March 25, 2021.'),('f088a160a5764dfab751fff1f0be3e57','Mariam Shewito',300,'The Washington Post','https://www.washingtonpost.com/world/2023/02/28/ethiopia-massacre-tigray-eritrea/','2024-08-30 22:45:19.171177','Killed by Eritrean forces','Adwa','Central Tigray','The Washington Post reported that Eritrean soldiers massacred more than 300 villagers in a week around the area of Mariam Shewito, based on accounts from witnesses and relatives of the victims.'),('f39ebbce0e31481ab43503680cb7b80a','Adwa, Enda Mariam Shewito',4,'Family Members and Relatives, The Washington Post, The Guardian','Family Members and Relatives, https://www.washingtonpost.com/world/2023/02/28/ethiopia-massacre-tigray-eritrea/, https://www.theguardian.com/global-development/2023/apr/20/the-hyenas-had-eaten-the-rest-survivors-speak-about-the-horrors-of-massacres-in-northern-tigray','2024-10-11 22:36:11.168447','Killed by Eritrean forces','Adwa','Central Tigray','Gebretsadik Haile was among the civilians massacred around Mariam Shewito by the Eritrean forces. He was killed along with four of his family members.'),('f5ef40f4d3a548f98fe9994c9b50df3a','Gheralta district, Arebay (ቁሸት ዓዲ ዓምዳይ)',8,'Family Members and Relatives','https://twitter.com/teborne/status/1342788054478712833','2024-04-09 17:11:46.204598','Killed by Eritrean forces','Degua Tembien','South Eastern Tigray','Hagos was killed along with 8 of his friends by the Eritrean forces in Gheralta, Adi Amday (ጣብያ ዓረባይ, ቑሸት ዓዲዓምዳይ).'),('f6429459c38f4b3b810a2ec29494970c','Adwa',10,'Family Members and Relatives','https://twitter.com/Helenkidane10/status/1361958066485395456','2024-05-03 13:48:13.519946','Killed by Eritrean forces','Adwa','Central Tigray','Gebremedhin Gebrekirstos and 10 other teenagers were killed by the Eritrean soldiers in front of his house on February 14, 2021.');
